#include <iostream>
#include <unistd.h>

int main() {
    pid_t pid = fork();

    if (pid == 0) {
        std::cout << "Child process" << std::endl;
    } else if (pid > 0) {
        std::cout << "Parent process" << std::endl;
    } else {
        std::cerr << "Fork failed" << std::endl;
        return 1;
    }

    return 0;
}
